// Preparar cenas para geração via Veo 2
const input = $input.first().json;
const data = input.scriptData || input;
const cenas = data.cenas || data.script?.cenas || [];

const tempDir = `${'/home/node/.n8n/temp'}/${data.videoId}`;

const fs = require('fs');
fs.mkdirSync(tempDir, { recursive: true });

const VISUAL_SUFFIX = ',divine golden light breaking through clouds, heavenly atmosphere, ancient Judea first century AD, cinematic composition, photorealistic, ultra detailed, no text overlay, no watermark, no modern elements, silent cinematic acting, no dialogue, quiet and peaceful scene';

return cenas.map((cena, i) => ({
  json: {
    videoId: data.videoId,
    cenaNumero: cena.numero || (i + 1),
    duracaoSegundos: Math.min(Math.max(cena.duracao_segundos || 6, 5), 8),
    prompt: cena.prompt_imagem + VISUAL_SUFFIX,
    tempDir,
    outputFile: `${tempDir}/scene_${String(i + 1).padStart(2, '0')}.mp4`,
    retryCount: 0
  }
}));

const loopData = $('Process Each Scene').item.json;
const driveData = $('Upload file').first().json;

if (!driveData.id) {
    throw new Error('Erro: O arquivo não foi salvo no Drive ou o ID não foi retornado.');
}

const videoUrl = `https://drive.google.com/uc?id=${driveData.id}&export=download&confirm=1`;

const staticData = $getWorkflowStaticData('global');
if (!staticData[loopData.videoId]) {
    staticData[loopData.videoId] = [];
}

staticData[loopData.videoId].push({
    numero: loopData.cenaNumero,
    duracao: loopData.duracaoSegundos,
    url: videoUrl,
    status: 'scene_ready'
});

return [{
  json: {
    videoId: loopData.videoId,
    cenaNumero: loopData.cenaNumero,
    duracaoSegundos: loopData.duracaoSegundos,
    videoUrl: videoUrl,
    status: 'scene_ready'
  }
}];

var staticData = ('global');
var videoId = .first().json.videoId;
var scenes = staticData[videoId] || [];
// Limpar após leitura
delete staticData[videoId];
return [{
  json: {
    videoId: videoId,
    totalScenes: scenes.length,
    scenes: scenes,
    status: 'all_scenes_ready'
  }
}];

